119→///                             // Socket is not ready anymore, stop reading
120→///                             break;
121→///                         }
122→///                         e => panic!("err={:?}", e), // Unexpected error
123→///                     }
124→///                 }
125→///             }
126→///         }
127→///     }
128→/// }
129→/// # }
130→/// ```
